import React from "react";
import Tooltip from './Tooltip';

const hostingerStyle = {
    wrapper: {
        position: 'relative',
        display: 'inherit',
        zIndex: '98',
        color: 'inherit',
        cursor: 'inherit',
        textAlign: 'center'
    },
    content: {
        backgroundColor: '#727586',
        color: '#FFF',
        fontSize: '16px',
        fontWeight: '400',
        padding: '0',
        lineHeight: 'normal',
    },
    tooltip: {
        backgroundColor: '#727586',
        borderRadius: '4px',
        padding: '4px 16px'
    },
    arrow: {
        borderTop: '0',
    },
};

const HostingerTooltip = ({children, content, styling }) => {

    /**
     * Overwrite style if defined
     */

    if(styling.wrapper) {
        hostingerStyle.wrapper = { ...hostingerStyle.wrapper, ...styling.wrapper }
    }

    return (
        <Tooltip
            content={ content }
            styles={ hostingerStyle }>
            { children }
        </Tooltip>
    );
}

export default HostingerTooltip;
